import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.B9unkguw.js";const h=JSON.parse('{"title":"Camera Tools","description":"","frontmatter":{},"headers":[],"relativePath":"tr/qgc-user-guide/fly_view/camera_tools.md","filePath":"tr/qgc-user-guide/fly_view/camera_tools.md"}'),i={name:"tr/qgc-user-guide/fly_view/camera_tools.md"};function n(s,e,c,l,d,m){return t(),o("div",null,e[0]||(e[0]=[r('<h1 id="camera-tools" tabindex="-1">Camera Tools <a class="header-anchor" href="#camera-tools" aria-label="Permalink to &quot;Camera Tools&quot;">​</a></h1><p>The camera tools are used to capture still images and video, and to configure the camera.</p><p>The camera capture and configuration options depend on the connected camera. The configuration options are selected using the panel gear icon. The configuration for a simple autopilot-connected camera are shown below.</p><p>When connected to camera that supports the <a href="https://mavlink.io/en/services/camera.html" target="_blank" rel="noreferrer">MAVLink Camera Protocol</a> you can additionally configure and use other camera services that it makes available. For example, if your camera supports video mode you will be able to switch between still image capture and video mode, and start/stop recording.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Most of the settings that are displayed depend on the camera (they are defined in its <a href="https://mavlink.io/en/services/camera_def.html" target="_blank" rel="noreferrer">MAVLink Camera Definition File</a>).</p><blockquote><p>A few common settings at the end are hard-coded: Photo Mode (Single/Time Lapse), Photo Interval (if Time Lapse), Reset Camera Defaults (sends a reset command to the camera), Format (storage) :::</p></blockquote><h3 id="video_instrument_page" tabindex="-1">Video Stream <a class="header-anchor" href="#video_instrument_page" aria-label="Permalink to &quot;Video Stream {#video_instrument_page}&quot;">​</a></h3><p>The video page is used to enable/disable video streaming. When enabled, you can start/stop the video stream, enable a grid overlay, change how the image fits the screen, and record the video locally with QGC.</p></div>',5)]))}const u=a(i,[["render",n]]);export{h as __pageData,u as default};
